35	use std::thread;
36	use ringbuf::{SharedRb, storage::Heap, traits::*};
37	
38	let rb = SharedRb::<Heap<i32>>::new(256);
39	let (mut prod, mut cons) = rb.split();
40	thread::spawn(move || {
