51	pub struct SharedRb<S: Storage + ?Sized> {
52	    read_index: CachePadded<AtomicUsize>,
53	    write_index: CachePadded<AtomicUsize>,
54	    read_held: AtomicBool,
55	    write_held: AtomicBool,
56	    storage: S,
57	}
